import { precacheAndRoute, cleanupOutdatedCaches } from 'workbox-precaching';
import { registerRoute } from 'workbox-routing';
import { NetworkOnly, CacheFirst } from 'workbox-strategies';
import { BackgroundSyncPlugin } from 'workbox-background-sync';
import { ExpirationPlugin } from 'workbox-expiration';
import { CacheableResponsePlugin } from 'workbox-cacheable-response';

// Clean up old caches from previous SW versions automatically
cleanupOutdatedCaches();

// Precaching all assets generated by Vite
// eslint-disable-next-line no-restricted-globals
precacheAndRoute(self.__WB_MANIFEST || []);

// Configure Background Sync for Supabase API mutations
const bgSyncPlugin = new BackgroundSyncPlugin('supabase-offline-queue', {
    maxRetentionTime: 24 * 60, // Retry for max of 24 Hours
});

const isSupabaseApi = ({ url }) => url.href.includes('.supabase.co/rest/v1/') || url.href.includes('.supabase.co/rpc/');

registerRoute(isSupabaseApi, new NetworkOnly({ plugins: [bgSyncPlugin] }), 'POST');
registerRoute(isSupabaseApi, new NetworkOnly({ plugins: [bgSyncPlugin] }), 'PATCH');
registerRoute(isSupabaseApi, new NetworkOnly({ plugins: [bgSyncPlugin] }), 'PUT');
registerRoute(isSupabaseApi, new NetworkOnly({ plugins: [bgSyncPlugin] }), 'DELETE');

// ─── Map Tile Caching (OpenStreetMap) ───────────────────────────────────────
// Strategy: CacheFirst — serve from local cache, only hit network if not cached.
// Tiles are automatically saved as the user browses the map with signal.
// Limit: 500 tiles max, expire after 30 days to keep maps up to date.
const isMapTile = ({ url }) =>
    url.hostname.endsWith('.tile.openstreetmap.org') ||
    url.hostname.endsWith('.tile.opentopomap.org');

registerRoute(
    isMapTile,
    new CacheFirst({
        cacheName: 'map-tiles-v1',
        plugins: [
            new CacheableResponsePlugin({ statuses: [0, 200] }),
            new ExpirationPlugin({
                maxEntries: 500,            // Keep last 500 tiles
                maxAgeSeconds: 30 * 24 * 60 * 60, // 30 days TTL
                purgeOnQuotaError: true,    // Auto-clean if disk is full
            }),
        ],
    }),
    'GET'
);

// Take control immediately when a new SW is installed
self.addEventListener('install', () => {
    self.skipWaiting();
});

// Claim all existing clients immediately on activation
self.addEventListener('activate', (event) => {
    event.waitUntil(self.clients.claim());
});

// Listen for SW_UPDATE message from the app to force a reload
self.addEventListener('message', (event) => {
    if (event.data && event.data.type === 'SKIP_WAITING') {
        self.skipWaiting();
    }
});


// Listen for incoming Push Events from the Server (e.g., Supabase Edge Function)
self.addEventListener('push', function (event) {
    let data = {};
    if (event.data) {
        try {
            data = event.data.json();
        } catch (e) {
            data = { body: event.data.text() };
        }
    }

    const title = data.title || 'Nueva Notificación';
    const options = {
        body: data.body || 'Tienes un nuevo mensaje en el CRM PickingUp',
        icon: '/icon-192.png',
        badge: '/icon-192.png',
        vibrate: [200, 100, 200],
        data: {
            url: data.url || '/'
        }
    };

    // Show the native OS notification
    event.waitUntil(self.registration.showNotification(title, options));
});

// Handle notification interaction (clicking the banner)
self.addEventListener('notificationclick', function (event) {
    event.notification.close();

    const targetUrl = event.notification.data?.url || '/';

    event.waitUntil(
        clients.matchAll({ type: 'window', includeUncontrolled: true }).then((windowClients) => {
            // If there's an existing open window, focus it and navigate
            for (let i = 0; i < windowClients.length; i++) {
                const client = windowClients[i];
                if (client.url.includes(targetUrl) && 'focus' in client) {
                    return client.focus();
                }
            }
            // If no window is open, open a new one
            if (clients.openWindow) {
                return clients.openWindow(targetUrl);
            }
        })
    );
});
